import os
import pickle
import joblib
import json
import boto3
import gcstorage
from google.cloud import storage as gcs
from azure.storage.blob import BlobServiceClient
import tempfile
import shutil
from pathlib import Path
import requests
import urllib.request

class ModelLoader:
    def __init__(self):
        self.model_path = os.getenv('MODEL_PATH')
        self.cloud_provider = os.getenv('CLOUD_PROVIDER', 'auto')
        self.bucket_name = os.getenv('BUCKET_NAME')
        self.aws_access_key = os.getenv('AWS_ACCESS_KEY_ID')
        self.aws_secret_key = os.getenv('AWS_SECRET_ACCESS_KEY')
        self.gcp_credentials = os.getenv('GOOGLE_APPLICATION_CREDENTIALS')
        self.azure_connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        self.model = None
        self.temp_dir = tempfile.mkdtemp()
        
    def detect_cloud_provider(self):
        if self.cloud_provider != 'auto':
            return self.cloud_provider
        
        if self.model_path.startswith('s3://'):
            return 'aws'
        elif self.model_path.startswith('gs://'):
            return 'gcp'
        elif self.model_path.startswith('https://') and 'blob.core.windows.net' in self.model_path:
            return 'azure'
        elif self.model_path.startswith('http://') or self.model_path.startswith('https://'):
            return 'http'
        else:
            return 'local'
    
    def get_latest_model_aws(self):
        s3 = boto3.client('s3',
                         aws_access_key_id=self.aws_access_key,
                         aws_secret_access_key=self.aws_secret_key)
        
        bucket = self.model_path.replace('s3://', '').split('/')[0]
        prefix = '/'.join(self.model_path.replace('s3://', '').split('/')[1:])
        
        response = s3.list_objects_v2(Bucket=bucket, Prefix=prefix)
        
        if 'Contents' not in response:
            return None
        
        latest = sorted(response['Contents'], key=lambda x: x['LastModified'], reverse=True)[0]
        
        local_path = os.path.join(self.temp_dir, os.path.basename(latest['Key']))
        s3.download_file(bucket, latest['Key'], local_path)
        
        return local_path
    
    def get_latest_model_gcp(self):
        client = gcs.Client()
        
        bucket_name = self.model_path.replace('gs://', '').split('/')[0]
        prefix = '/'.join(self.model_path.replace('gs://', '').split('/')[1:])
        
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=prefix))
        
        if not blobs:
            return None
        
        latest = sorted(blobs, key=lambda x: x.updated, reverse=True)[0]
        
        local_path = os.path.join(self.temp_dir, os.path.basename(latest.name))
        latest.download_to_filename(local_path)
        
        return local_path
    
    def get_latest_model_azure(self):
        blob_service_client = BlobServiceClient.from_connection_string(self.azure_connection_string)
        
        container_name = self.model_path.split('/')[3]
        prefix = '/'.join(self.model_path.split('/')[4:])
        
        container_client = blob_service_client.get_container_client(container_name)
        blobs = container_client.list_blobs(name_starts_with=prefix)
        
        blob_list = list(blobs)
        if not blob_list:
            return None
        
        latest = sorted(blob_list, key=lambda x: x.last_modified, reverse=True)[0]
        
        local_path = os.path.join(self.temp_dir, os.path.basename(latest.name))
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=latest.name)
        
        with open(local_path, 'wb') as f:
            f.write(blob_client.download_blob().readall())
        
        return local_path
    
    def get_latest_model_http(self):
        local_path = os.path.join(self.temp_dir, 'model_' + os.path.basename(self.model_path))
        urllib.request.urlretrieve(self.model_path, local_path)
        return local_path
    
    def get_latest_model_local(self):
        path = Path(self.model_path)
        if path.is_file():
            return str(path)
        elif path.is_dir():
            files = sorted(path.glob('*'), key=os.path.getmtime, reverse=True)
            if files:
                return str(files[0])
        return None
    
    def load_model_file(self, file_path):
        ext = os.path.splitext(file_path)[1].lower()
        
        if ext == '.pkl' or ext == '.pickle':
            with open(file_path, 'rb') as f:
                return pickle.load(f)
        elif ext == '.joblib':
            return joblib.load(file_path)
        elif ext == '.json':
            with open(file_path, 'r') as f:
                return json.load(f)
        else:
            with open(file_path, 'rb') as f:
                return pickle.load(f)
    
    def load_model(self):
        provider = self.detect_cloud_provider()
        
        if provider == 'aws':
            model_file = self.get_latest_model_aws()
        elif provider == 'gcp':
            model_file = self.get_latest_model_gcp()
        elif provider == 'azure':
            model_file = self.get_latest_model_azure()
        elif provider == 'http':
            model_file = self.get_latest_model_http()
        else:
            model_file = self.get_latest_model_local()
        
        if model_file:
            self.model = self.load_model_file(model_file)
            return self.model
        else:
            raise Exception("No model found at specified path")
    
    def predict(self, data):
        if self.model is None:
            raise Exception("Model not loaded")
        
        if hasattr(self.model, 'predict'):
            return self.model.predict(data)
        elif callable(self.model):
            return self.model(data)
        else:
            raise Exception("Model does not support prediction")
    
    def cleanup(self):
        if os.path.exists(self.temp_dir):
            shutil.rmtree(self.temp_dir)


def main():
    loader = ModelLoader()
    
    print(f"Loading model from: {loader.model_path}")
    print(f"Detected cloud provider: {loader.detect_cloud_provider()}")
    
    model = loader.load_model()
    print("Model loaded successfully")
    
    return loader


